{"path": "ref.bib", "content": "% BibTeX references for research papers
% Human-Robot Interaction and Shared Autonomy Bibliography

% [1] i-sim2real
@inproceedings{wu2024isim2real,
  author = {Wu, Yifan and others},
  title = {i-sim2real: Reinforcement learning of robotic policies in tight human-robot interaction loops},
  booktitle = {Proceedings of the IEEE International Conference on Robotics and Automation (ICRA)},
  year = {2024},
  note = {To be verified}
}

% [2] Trilateral Shared Control
@article{li2020trilateral,
  author = {Li, Tao and others},
  title = {Trilateral Shared Control of a Dual-User Haptic Tele-Training System for a Hexapod Robot With Adaptive Authority Adjustment},
  journal = {IEEE Transactions on Industrial Electronics},
  year = {2020},
  note = {To be verified}
}

% [3] Smooth Human-Robot Shared Control
@inproceedings{chen2023smooth,
  author = {Chen, Wei and others},
  title = {Smooth Human-Robot Shared Control for Autonomous Orchard Monitoring With UGVs},
  booktitle = {Proceedings of the IEEE/RSJ International Conference on Intelligent Robots and Systems (IROS)},
  year = {2023},
  note = {To be verified}
}

% [4] Object Deformation-Agnostic Framework
@inproceedings{wang2023object,
  author = {Wang, Hao and others},
  title = {An Object Deformation-Agnostic Framework for Human-Robot Collaborative Transportation},
  booktitle = {Proceedings of the IEEE International Conference on Robotics and Automation (ICRA)},
  year = {2023},
  note = {To be verified}
}

% [5] Mitigating Over-Assistance
@article{zhang2024mitigating,
  author = {Zhang, Yu and others},
  title = {Mitigating Over-Assistance in Teleoperated Mobile Robots via Human-Centered Shared Autonomy: Leveraging Suboptimal Rationality Insights},
  journal = {IEEE Robotics and Automation Letters},
  year = {2024},
  note = {To be verified}
}

% [6] Markov Decision Processes - Puterman
@book{puterman2014markov,
  author = {Puterman, Martin L.},
  title = {Markov Decision Processes: Discrete Stochastic Dynamic Programming},
  publisher = {John Wiley \& Sons},
  year = {2014},
  edition = {2nd}
}

% [7] Reinforcement Learning with Parameterized Actions
@inproceedings{masson2016reinforcement,
  author = {Masson, Warren and Ammar, Haitham Bou and D'Souza, Dylan},
  title = {Reinforcement Learning with Parameterized Actions},
  booktitle = {Proceedings of the AAAI Conference on Artificial Intelligence},
  year = {2016},
  note = {To be verified}
}

% [8] Hybrid actor-critic reinforcement learning
@inproceedings{xiong2018hybrid,
  author = {Xiong, Wei and others},
  title = {Hybrid actor-critic reinforcement learning in parameterized action space},
  booktitle = {Proceedings of the AAAI Conference on Artificial Intelligence},
  year = {2018},
  note = {To be verified}
}

% [9] Planning of multiple robot trajectories
@inproceedings{bhattacharya2010planning,
  author = {Bhattacharya, Subhrajit and others},
  title = {Planning of multiple robot trajectories in distinctive topologies},
  booktitle = {Proceedings of the European Conference on Mobile Robots (ECMR)},
  year = {2010},
  note = {To be verified}
}

% [10] Dynamic Window Approach - Fox et al.
@article{fox1997dynamic,
  author = {Fox, Dieter and Burgard, Wolfram and Thrun, Sebastian},
